# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

from kafka import AdminClient
from kafka.errors import TopicAlreadyExistsError
from argparse import ArgumentParser

parser = ArgumentParser(description="Kafka topic administration")
parser.add_argument("--topic", help="Topic name", required=True)
parser.add_argument("--partitions", type=int, help="Number of partitions", default=1)
parser.add_argument("--replication", type=int, help="Replication factor", default=1)

args = parser.parse_args()

# Create Kafka admin client
client = AdminClient({
    "bootstrap.servers": "kafka-broker:9092",  # Replace with actual broker address
})

try:
    # Create topic
    client.create_topic(
        name=args.topic,
        num_partitions=args.partitions,
        replication_factor=args.replication,
    )
    print(f"Topic '{args.topic}' created successfully.")
except TopicAlreadyExistsError:
    print(f"Topic '{args.topic}' already exists.")

# Close Kafka client
client.close()